import type * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import * as HttpApiSchema from "./HttpApiSchema.js"
import type * as HttpClientError from "./HttpClientError.js"
import type * as HttpClientResponse from "./HttpClientResponse.js"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * Represents a single Server-Sent Event message.
 *
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

/**
 * Formats an `SSEMessage` into the SSE wire format.
 *
 * @since 1.0.0
 * @category encoding
 */
export const formatMessage = (message: SSEMessage): string => {
  let output = ""
  if (message.event !== undefined) {
    output += `event: ${message.event}\n`
  }
  if (message.id !== undefined) {
    output += `id: ${message.id}\n`
  }
  if (message.retry !== undefined) {
    output += `retry: ${message.retry}\n`
  }
  const lines = message.data.split("\n")
  for (const line of lines) {
    output += `data: ${line}\n`
  }
  return output + "\n"
}

/**
 * JSON-encodes the given value and formats it as an SSE wire-format message.
 *
 * @since 1.0.0
 * @category encoding
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

/**
 * @internal
 */
const getTag = (ast: AST.AST): string | undefined => {
  switch (ast._tag) {
    case "TypeLiteral": {
      const ps = ast.propertySignatures.find((ps) => ps.name === "_tag")
      if (ps === undefined || ps.type._tag !== "Literal" || typeof ps.type.literal !== "string") {
        return undefined
      }
      return ps.type.literal
    }
    case "Transformation": {
      return getTag(ast.to)
    }
    case "Refinement": {
      return getTag(ast.from)
    }
    case "Suspend": {
      return getTag(ast.f())
    }
    default: {
      return undefined
    }
  }
}

/**
 * Creates an encoder for a single event schema, producing an SSE wire-format
 * message string.
 *
 * @since 1.0.0
 * @category encoding
 */
export const makeEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
) => {
  const encode = Schema.encode(Schema.parseJson(schema))
  return (a: A) => ParseResult.map(encode(a), (data) => formatMessage({ data }))
}

/**
 * Creates an encoder for a (possibly tagged union) success schema.
 *
 * For tagged union schemas, the `event` field of the resulting SSE message
 * is set to the `_tag` of the matched member (or the `event` set via
 * `HttpApiSchema.withSSE`, if present). For non-union schemas, this falls
 * back to `makeEventEncoder`.
 *
 * @since 1.0.0
 * @category encoding
 */
export const makeUnionEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
) => {
  if (schema.ast._tag !== "Union") {
    return makeEventEncoder(schema)
  }
  const schemas = new Set<Schema.Schema.Any>()
  HttpApiSchema.deunionize(schemas, schema)
  const encoders = new Map<string, (a: any) => ParseResult.ParseResult<string>>()
  for (const member of schemas) {
    const tag = getTag(member.ast)
    if (tag === undefined) continue
    const event = HttpApiSchema.getSSE(member.ast)?.event ?? tag
    const encode = Schema.encode(Schema.parseJson(member))
    encoders.set(tag, (a) => ParseResult.map(encode(a), (data) => formatMessage({ data, event })))
  }
  return (a: A): ParseResult.ParseResult<string> => {
    const tag = (a as any)._tag
    const encoder = encoders.get(tag)
    if (encoder === undefined) {
      return ParseResult.fail(new ParseResult.Type(schema.ast, a, `No SSE encoder found for tag "${tag}"`))
    }
    return encoder(a)
  }
}

